INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '2b8fd589-ae32-4551-8373-14590a304d4d',
  '00000000-0000-0000-0000-000000000001',
  $escape$NATS JetStream — Decoupling, Async Processing, and Load Leveling Done Right$escape$,
  $escape$Without a queue, your API handler is directly coupled to every downstream operation — if email sending spikes latency, your HTTP response does too. NATS JetStream breaks this with persistent, replay-capable subjects. Publish once to a subject like `orders.created`; multiple consumer groups pull at their own pace without blocking the publisher.

Load leveling in NATS uses push or pull consumers. Pull consumers (preferred for workers) let each instance call `Fetch(batch)` only when ready, preventing fast publishers from overwhelming slow processors. A durable consumer with `DeliverPolicy: DeliverAllPolicy` guarantees no message is lost across restarts.

Critically, NATS uses per-subject acknowledgment — `msg.Ack()`, `msg.Nak()`, or `msg.NakWithDelay(d)` for retry backoff. A Nak requeues immediately; `NakWithDelay` implements exponential backoff without external tooling. Combined with `MaxDeliver` on the stream, you get dead-letter semantics natively. This lets API handlers return 202 Accepted instantly while workers drain the subject at sustainable throughput.$escape$,
  $escape$js, _ := jetstream.New(nc)

stream, _ := js.CreateStream(ctx, jetstream.StreamConfig{
    Name:     "ORDERS",
    Subjects: []string{"orders.>"},
})

consumer, _ := stream.CreateOrUpdateConsumer(ctx, jetstream.ConsumerConfig{
    Durable:       "order-processor",
    AckPolicy:     jetstream.AckExplicitPolicy,
    MaxDeliver:    5,
    BackOff:       []time.Duration{2*time.Second, 10*time.Second, 30*time.Second},
})

for {
    msgs, _ := consumer.Fetch(10)
    for msg := range msgs.Messages() {
        if err := process(msg); err != nil {
            msg.NakWithDelay(5 * time.Second)
            continue
        }
        msg.Ack()
    }
}$escape$,
  $escape$go$escape$,
