INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '711f2133-8253-452a-bb89-4d705ce8ba3d',
  '00000000-0000-0000-0000-000000000001',
  $escape$NATS JetStream KV — Cache-Aside Pattern Without Adding Redis$escape$,
  $escape$NATS JetStream's built-in Key-Value store gives you a distributed cache without bolting on Redis or Memcached. Every KV bucket is backed by a JetStream stream — replicated, persisted, and TTL-aware by default.

The cache-aside pattern maps directly: call `kv.Get(ctx, key)`; if `jetstream.ErrKeyNotFound` is returned, fetch from Postgres, marshal the result, and `kv.Put(ctx, key, data)`. The bucket TTL handles expiry automatically — no manual cleanup jobs.

Where this pays off: high-read, low-write entities like user profiles, feature flags, and lookup tables. A 5-minute TTL on a `user-cache` bucket routinely cuts Postgres read traffic by 80%+ under normal fan-out patterns. NATS serves the cached bytes in-memory from the same connection your services already hold open.

Two sharp edges: TTL is bucket-scoped, not per-key — use separate buckets for mixed expiry needs. For write-through invalidation, call `kv.Delete(ctx, key)` before committing to the DB; skipping this risks returning stale data on the next read within the TTL window.$escape$,
  $escape$kv, _ := js.CreateOrUpdateKeyValue(ctx, jetstream.KeyValueConfig{
	Bucket:   "user-cache",
	TTL:      5 * time.Minute,
	Replicas: 1,
})

entry, err := kv.Get(ctx, userID)
if errors.Is(err, jetstream.ErrKeyNotFound) {
	user, _ := db.GetUser(ctx, userID)
	data, _ := json.Marshal(user)
	kv.Put(ctx, userID, data)
	return user
}
var user User
json.Unmarshal(entry.Value(), &user)
return user$escape$,
