INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '72852ad9-f817-4b0c-80c9-d5896e2215ab',
  '00000000-0000-0000-0000-000000000001',
  $escape$NATS JetStream Idempotency — Safe Duplicate Handling in Consumers$escape$,
  $escape$NATS JetStream's publish-side deduplication (via the `Nats-Msg-Id` header and the stream's `DuplicateWindow`) only catches duplicates at ingestion time — once a message is in the stream, consumers are on their own. With `AckExplicit` delivery policy, any unacked or `Nak()`'d message is redelivered, making consumer-side idempotency essential.

The pattern: require publishers to set `Nats-Msg-Id` as a message header (JetStream persists it on the message metadata). In the consumer, perform an atomic check-and-set — using Redis `SET NX` or a database upsert — against that ID before processing. If the key already exists, the message was already handled: call `msg.Ack()` to drain it from the pending set without reprocessing.

One subtle trap: if processing succeeds but `msg.Ack()` fails, the message redelivers. Your idempotency store prevents double execution, but you still need `Ack()` to succeed — never delete the idempotency key on success. Retain it for at least your stream's `MaxAge` plus redelivery window.

With `nats.MaxDeliver(5)` on the consumer binding, unresolvable failures are automatically dead-lettered after five attempts, keeping your pending count clean.$escape$,
  $escape$sub, _ := js.Subscribe("orders.placed", func(msg *nats.Msg) {
	msgID := msg.Header.Get("Nats-Msg-Id")
	if msgID == "" {
		msg.Nak()
		return
	}

	// Atomic guard — SET NX prevents concurrent duplicate processing
	if !store.SetNX(ctx, "processed:"+msgID, 1, 48*time.Hour).Val() {
		msg.Ack() // already handled, drain from pending
		return
	}

	if err := processOrder(msg.Data); err != nil {
		store.Del(ctx, "processed:"+msgID) // rollback guard on failure
		msg.Nak()
		return
	}
	msg.Ack()
},
	nats.Durable("order-processor"),
	nats.AckExplicit(),
	nats.MaxDeliver(5),
)$escape$,
  $escape$go$escape$,
