INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '229b05d5-c988-4634-9ba6-f170679fce06',
  '00000000-0000-0000-0000-000000000001',
  $escape$NATS JetStream Dead Letter Queues — Poison Message Handling and Backoff Strategies$escape$,
  $escape$NATS JetStream has no native DLQ, but the pattern composes cleanly. Set MaxDeliver on your consumer to cap total attempts. Once exhausted, JetStream emits an advisory to $JS.EVENT.ADVISORY.CONSUMER.MAX_DELIVERIES.<stream>.<consumer> — subscribe there to capture the original stream sequence, then republish to a dedicated DEAD.> stream for post-mortem inspection.

For backoff, skip manual NakWithDelay math. NATS 2.9+ supports BackOff []time.Duration directly on ConsumerConfig — declare your full retry schedule upfront and JetStream handles redelivery timing without application-side logic. [5s, 30s, 2m] means first retry after 5s, second after 30s, third after 2m. MaxDeliver should equal len(BackOff) + 1.

If you need runtime flexibility, call msg.NakWithDelay(delay) where delay derives from meta.NumDelivered via msg.Metadata(). Note: AckWait acts as a floor — if your backoff delay is shorter than AckWait, the server requeues at AckWait expiry instead.

Bind your DLQ stream to DEAD.> with a long MaxAge and MaxDeliver: 1 — preserve these messages for replay, never re-process them automatically.$escape$,
  $escape$// NATS 2.9+: declare full retry schedule on the consumer
cfg := jetstream.ConsumerConfig{
    Durable:    "orders-worker",
    MaxDeliver: 4, // len(BackOff) + 1
    AckPolicy:  jetstream.AckExplicitPolicy,
    BackOff:    []time.Duration{5 * time.Second, 30 * time.Second, 2 * time.Minute},
}

// When MaxDeliver is exhausted, capture via advisory and route to DLQ
nc.Subscribe("$JS.EVENT.ADVISORY.CONSUMER.MAX_DELIVERIES.ORDERS.orders-worker",
    func(m *nats.Msg) {
        var adv server.ConsumerMaxDeliveriesAdvisoryV1
        json.Unmarshal(m.Data, &adv)
        raw, _ := js.GetMsg(ctx, "ORDERS", adv.StreamSeq)
        nc.Publish("DEAD.orders", raw.Data)
    },
)$escape$,
  $escape$go$escape$,
