INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '081ab7fb-97a5-4df7-8a2c-9c17977a5ef4',
  '00000000-0000-0000-0000-000000000001',
  $escape$NATS JetStream vs Kafka — Partitions, Consumer Groups, and Log Compaction Mapped$escape$,
  $escape$Kafka partitions, consumer groups, and log compaction all have NATS JetStream equivalents — but the mental model shifts significantly.

Instead of partitions, NATS uses subject hierarchies for sharding: route `orders.us.*` and `orders.eu.*` to separate filtered stream consumers, achieving parallel processing without explicit partition assignment.

Consumer groups map to queue subscriptions on a durable consumer. Multiple subscribers sharing the same `QueueGroup` name and `Durable` name compete for messages — JetStream distributes work and tracks ack state per-consumer, not per-partition.

Offset management uses sequence numbers (uint64, per-stream). `DeliverByStartSequence` lets you seek to any point in the log. `AckPolicy: explicit` gives at-least-once delivery; use `nats.StartSequence(n)` on re-subscribe to resume from a known checkpoint without storing offsets externally.

Log compaction maps directly to `MaxMsgsPerSubject: 1` on a stream — JetStream retains only the latest message per subject key, purging older ones. This is exactly how the built-in Key-Value store (`js.CreateKeyValue`) works under the hood: a stream with compaction semantics and a structured subject scheme baked in.$escape$,
  $escape$js, _ := nc.JetStream()

// Log compaction — retain only last message per subject key
js.AddStream(&nats.StreamConfig{
    Name:              "ORDERS",
    Subjects:          []string{"orders.*"},
    MaxMsgsPerSubject: 1,
})

// Consumer group — shared durable queue subscriber
js.QueueSubscribe("orders.*", "processors", handler,
    nats.Durable("order-processor"),
    nats.AckExplicit(),
)

// Offset seek — replay from a specific sequence number
js.Subscribe("orders.*", handler,
    nats.Durable("audit-consumer"),
    nats.StartSequence(1042),
)$escape$,
  $escape$go$escape$,
