INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '57f09920-aae1-40a9-8d89-d06872fe6438',
  '00000000-0000-0000-0000-000000000001',
  $escape$NATS JetStream vs RabbitMQ — Exchanges, Acks, and Prefetch Translated$escape$,
  $escape$NATS JetStream replaces RabbitMQ's exchange/routing-key model with subject-based routing. There are no exchange types — subjects like `orders.us.placed` serve as both address and filter. A Stream captures messages matching a pattern (`orders.>`), and a Consumer narrows that with `FilterSubject`. The `*` wildcard matches one token; `>` matches the rest of the path — equivalent to a topic exchange binding.

For acknowledgements, JetStream consumers use `AckExplicit` by default. Call `msg.Ack()` to confirm, `msg.Nak()` to requeue (or `msg.NakWithDelay(d)` for backoff), `msg.Term()` to dead-letter without requeue, and `msg.InProgress()` to reset the `AckWait` timer mid-processing. No separate DLX wiring needed — dead-lettering is per-message.

Prefetch count maps directly to `MaxAckPending` on the consumer config. Setting it to 10 means at most 10 unacked messages are in-flight per consumer at once. For pull consumers, `Fetch(n)` is naturally bounded by `MaxAckPending`, giving you explicit backpressure without a separate QoS call. Unlike RabbitMQ's channel-level `basic.qos`, this is scoped per consumer — no shared state across workers.$escape$,
  $escape$js, _ := nc.JetStream()

js.AddStream(&nats.StreamConfig{
    Name:     "ORDERS",
    Subjects: []string{"orders.>"},
})

sub, _ := js.PullSubscribe("orders.us.*", "worker",
    nats.ManualAck(),
    nats.MaxAckPending(10), // prefetch equivalent
)

msgs, _ := sub.Fetch(5, nats.MaxWait(2*time.Second))
for _, msg := range msgs {
    if err := process(msg); err != nil {
        msg.NakWithDelay(5 * time.Second) // requeue with backoff
        continue
    }
    msg.Ack()
}$escape$,
  $escape$go$escape$,
