INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ad90e43c-3adf-45fe-8e81-c017b09304bf',
  '00000000-0000-0000-0000-000000000001',
  $escape$NATS JetStream — Subject Routing and At-Least-Once Delivery Without the Guesswork$escape$,
  $escape$JetStream turns NATS from a fire-and-forget bus into a durable messaging layer. Streams capture messages published to subject wildcards — define a stream on `orders.>` and every message to `orders.created`, `orders.paid`, or `orders.cancelled` is persisted. Consumers then pull or push from that stream with configurable AckPolicy.

For at-least-once delivery, set `AckPolicy: nats.AckExplicitPolicy` on your consumer. Each delivered message must be acknowledged with `msg.Ack()` within the `AckWait` window (default 30s). Unacked messages are redelivered up to `MaxDeliver` times. Use `msg.Nak()` to signal failure and trigger immediate redelivery, or `msg.NakWithDelay(5 * time.Second)` for backoff.

Subject-based routing is the key architectural lever: fan-out by publishing to `events.user.signup` and binding multiple consumers across different streams to overlapping wildcards. Unlike Kafka partitions, NATS subject hierarchy is free-form — no pre-declared topology needed. Combine with `FilterSubject` on a consumer to scope a single stream into independent processing lanes without duplicating storage.$escape$,
  $escape$js, _ := nc.JetStream()

// Create stream capturing all order events
js.AddStream(&nats.StreamConfig{
    Name:     "ORDERS",
    Subjects: []string{"orders.>"},
    Storage:  nats.FileStorage,
})

// Durable push consumer with explicit ack
js.Subscribe("orders.created", func(msg *nats.Msg) {
    process(msg.Data)
    msg.Ack() // required — no ack = redelivery after AckWait
}, nats.Durable("order-processor"), nats.AckExplicit())
$escape$,
  $escape$go$escape$,
