INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ad78e893-3d08-48dd-acf5-6bba8be97568',
  '00000000-0000-0000-0000-000000000001',
  $escape$NATS JetStream — Horizontal Consumer Scaling Without Partition Rebalancing$escape$,
  $escape$JetStream pull consumers scale horizontally without coordination: spin up N instances sharing the same durable consumer name and NATS distributes pending messages across all active fetchers — no leader election, no rebalancing delay. Each `Fetch()` call atomically reserves a batch, so there's no double-delivery risk.

For explicit partitioning, shard by subject prefix: publish to `orders.{shard}` where shard is `crc32(key) % N`, then bind each consumer instance to a distinct `FilterSubject`. This gives predictable key locality — essential for ordered-per-key processing. Unlike Kafka, there's no broker-side partition metadata to rebalance when you add consumers; deploy an instance with a new `FilterSubject` and it starts consuming immediately.

To increase fan-out, attach additional durable pull consumers with disjoint `FilterSubjects` on the same stream. NATS retains the stream independently of consumer count, so late-attached consumers replay from any `DeliverPolicy` without manual offset management. Monitor lag via `nats consumer info <stream> <consumer>` or scrape the `nats_consumer_num_pending` Prometheus metric per shard.$escape$,
  $escape$js, _ := jetstream.New(nc)

shard := crc32.ChecksumIEEE([]byte(orderID)) % 8

cons, _ := js.CreateOrUpdateConsumer(ctx, "ORDERS", jetstream.ConsumerConfig{
    Durable:       fmt.Sprintf("processor-shard-%d", shard),
    FilterSubject: fmt.Sprintf("orders.%d", shard),
    AckPolicy:     jetstream.AckExplicitPolicy,
    MaxAckPending: 100,
})

batch, _ := cons.Fetch(10, jetstream.FetchMaxWait(2*time.Second))
for msg := range batch.Messages() {
    process(msg.Data())
    msg.Ack()
}$escape$,
  $escape$go$escape$,
